parameters.jsCode:
try {
  const trigger = $('Trigger - Execute Workflow').first().json;
  const clinicApiResult = $('A - Consultar Disponibilidad API Clinica').first().json;
  const calendlyResult = $('A - Consultar Disponibilidad Calendly').first().json;

  const slots = [];

  // Procesar slots de API clinica
  if (clinicApiResult && !clinicApiResult.error && clinicApiResult.slots) {
    const apiSlots = Array.isArray(clinicApiResult.slots) ? clinicApiResult.slots : [];
    for (const slot of apiSlots) {
      slots.push({
        datetime: slot.datetime || slot.start || slot.time,
        source: 'clinic_api'
      });
    }
  }

  // Procesar slots de Calendly
  if (calendlyResult && !calendlyResult.error && calendlyResult.collection) {
    const calSlots = Array.isArray(calendlyResult.collection) ? calendlyResult.collection : [];
    for (const slot of calSlots) {
      const dt = slot.start_time || slot.time;
      // Evitar duplicados
      if (!slots.find(s => s.datetime === dt)) {
        slots.push({
          datetime: dt,
          source: 'calendly'
        });
      }
    }
  }

  // Limitar a 5 slots maximo
  const limitedSlots = slots.slice(0, 5);

  if (limitedSlots.length === 0) {
    return [{ json: { success: false, error: 'No hay disponibilidad para la fecha solicitada.', slots: [] } }];
  }

  return [{ json: { success: true, message: `Se encontraron ${limitedSlots.length} horarios disponibles.`, slots: limitedSlots } }];
} catch (e) {
  return [{ json: { success: false, error: 'Error al consultar disponibilidad: ' + e.message, slots: [] } }];
}

const trigger = $('Trigger - Execute Workflow').first().json;
const clinic = $('B - Obtener Config Clinica').first().json;

const errors = [];
if (!trigger.phone) errors.push('Telefono del paciente es obligatorio');
if (!trigger.service) errors.push('Servicio es obligatorio');
if (!trigger.preferred_date) errors.push('Fecha preferida es obligatoria');
if (!trigger.preferred_time) errors.push('Hora preferida es obligatoria');

// Validar formato fecha YYYY-MM-DD
if (trigger.preferred_date && !/^\d{4}-\d{2}-\d{2}$/.test(trigger.preferred_date)) {
  errors.push('Formato de fecha invalido. Use YYYY-MM-DD');
}
// Validar formato hora HH:MM
if (trigger.preferred_time && !/^\d{2}:\d{2}$/.test(trigger.preferred_time)) {
  errors.push('Formato de hora invalido. Use HH:MM');
}

if (errors.length > 0) {
  return [{ json: { success: false, error: errors.join('. '), validation_failed: true } }];
}

return [{ json: { ...trigger, clinic_config: clinic, validation_failed: false, datetime: trigger.preferred_date + 'T' + trigger.preferred_time + ':00' } }];

try {
  const dbResult = $('B - Guardar Cita en BD').first().json;
  const trigger = $('Trigger - Execute Workflow').first().json;

  if (!dbResult || !dbResult.id) {
    return [{ json: { success: false, error: 'Error al guardar la cita en la base de datos.' } }];
  }

  const dt = new Date(dbResult.datetime);
  const fecha = dt.toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'Europe/Madrid' });
  const hora = dt.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Madrid' });

  return [{ json: {
    success: true,
    message: `Cita creada el ${fecha} a las ${hora} para ${dbResult.service}`,
    appointment_id: dbResult.id,
    datetime: dbResult.datetime,
    confirmation_code: $('B - Crear en API Clinica').first().json.id || dbResult.id
  }}];
} catch (e) {
  return [{ json: { success: false, error: 'Error al procesar la respuesta de creacion: ' + e.message } }];
}

const items = $('C - Obtener Cita').all();
if (!items || items.length === 0 || !items[0].json.id) {
  return [{ json: { success: false, error: 'Cita no encontrada o no pertenece a este telefono.', not_found: true } }];
}
return [{ json: { ...items[0].json, not_found: false } }];

try {
  return [{ json: { success: true, message: 'Cita cancelada correctamente.' } }];
} catch (e) {
  return [{ json: { success: false, error: 'Error al cancelar la cita: ' + e.message } }];
}

const items = $('D - Obtener Cita Actual').all();
if (!items || items.length === 0 || !items[0].json.id) {
  return [{ json: { success: false, error: 'Cita no encontrada o no pertenece a este telefono.', not_found: true } }];
}
const trigger = $('Trigger - Execute Workflow').first().json;
if (!trigger.preferred_date || !trigger.preferred_time) {
  return [{ json: { success: false, error: 'Debe indicar la nueva fecha y hora para reprogramar.', not_found: true } }];
}
return [{ json: { ...items[0].json, new_datetime: trigger.preferred_date + 'T' + trigger.preferred_time + ':00', not_found: false } }];

