try {
  const dbResult = $('D - Actualizar BD Reprogramar').first().json;
  if (!dbResult || !dbResult.id) {
    return [{ json: { success: false, error: 'Error al reprogramar la cita en la base de datos.' } }];
  }
  const dt = new Date(dbResult.datetime);
  const fecha = dt.toLocaleDateString('es-ES', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'Europe/Madrid' });
  const hora = dt.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Madrid' });
  return [{ json: {
    success: true,
    message: `Cita reprogramada para el ${fecha} a las ${hora}.`,
    appointment_id: dbResult.id,
    datetime: dbResult.datetime
  }}];
} catch (e) {
  return [{ json: { success: false, error: 'Error al procesar reprogramacion: ' + e.message } }];
}

try {
  const appointments = $('F - Obtener Proximas Citas').all().map(item => item.json);

  if (!appointments || appointments.length === 0 || !appointments[0].id) {
    return [{ json: { success: true, message: 'No tienes citas programadas proximamente.', appointments: [] } }];
  }

  const lines = appointments.map((apt, i) => {
    const dt = new Date(apt.datetime);
    const fecha = dt.toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long', timeZone: 'Europe/Madrid' });
    const hora = dt.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit', timeZone: 'Europe/Madrid' });
    const estado = apt.status === 'confirmed' ? ' (Confirmada)' : '';
    return `${i + 1}. ${apt.service} - ${fecha} a las ${hora}${estado}`;
  });

  return [{ json: {
    success: true,
    message: 'Tus proximas citas:\n' + lines.join('\n'),
    appointments: appointments
  }}];
} catch (e) {
  return [{ json: { success: false, error: 'Error al obtener tus citas: ' + e.message } }];
}
